def get_parameters():
 global start
 global Mikrotik
 global port
 global info
 global help
 global optp
 page = str(sys.argv)
 H  = "['AllInOne.py', '-H']"
 S  = "['AllInOne.py', '-S']"
 I  = "['AllInOne.py', '-I']"
 M  = "['AllInOne.py', '-M']"
 R  = "['AllInOne.py', '-R']"
